var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`채리엇. 수송 모드에서 커뮤니케이션 모드로 전환.`,JPN:`チャリオット。輸送モードよりコミュニケーションモードへ移行。`,ENG:`Chariot, switching from transportation mode to communication mode.`,TWN:`步戰車柴瑞爾，從運輸模式切換到交流模式。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`시민 여러분의 안전을 위해 헌신하는 블랙 타이드, 저는 방어 수송차량 채리엇입니다. 무엇을 도와드릴까요?`,JPN:`私は市民の皆様の安全のために尽くすブラックタイドの防衛輸送車両チャリオットです。何かお困りですか？`,ENG:`Black Tide is dedicated to the safety of citizens. I'm Chariot, a defensive transport vehicle. How may I help you?`,TWN:`這裡是致力於保護公民安全的黑潮，我是防禦型運輸車輛步戰車柴瑞爾。有什麼需要幫忙的嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`......귀하의 종신계약에 대한 요구를 접수.`,JPN:`……貴方の終身契約に関する要請を受理いたしました。`,ENG:`Your lifetime contract offer has been received.`,TWN:`……我接受您的終身契請求。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`블랙 타이드의 대원은 시민 안전을 최우선으로 둡니다.`,JPN:`ブラックタイドの隊員は、市民の安全を最優先としています。`,ENG:`We, the members of Black Tide, put the citizens' safety before everything.`,TWN:`黑潮的隊員們始終把市民的人身安全放在第一位。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`사장님이 경영하는 기업은 그간 치안 유지에 공헌해 왔습니다.`,JPN:`社長は企業の経営を通じて、治安維持に多大な貢献をされてきました。`,ENG:`Your company has contributed to the maintenance of public peace.`,TWN:`老闆經營的企業，至今為止都對維持治安做出很大的貢獻。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`치안을 위협하는 지시가 없는 한, 사장님과 채리엇의 신뢰 관계는 견고할 것입니다.`,JPN:`治安を脅かす指示がなされない限り、社長とチャリオットの信頼関係が揺らぐことはないでしょう。`,ENG:`Chariot will remain on good terms with you, so long as you respect its wishes to protect public peace.`,TWN:`只要老闆沒有做出破壞治安的指示，我們之間的信任關係就會非常牢固。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`VEHICLE_TIDE_NULL_NULL`,text:{KOREA:`감사합니다.`,JPN:`感謝申し上げます。`,ENG:`Thank you.`,TWN:`非常感謝。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`VEHICLE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};